'use strict';

var FIXTURES = FIXTURES || {};

if ('serviceWorker' in navigator) {
  window.addEventListener('load', function() {
    navigator.serviceWorker.register('service-worker.js').then(function(registration) {
      console.log('ServiceWorker registration successful with scope: ', registration.scope);
    }).catch(function(err) {
      console.log('ServiceWorker registration failed: ', err);
    });
  });
}



window.onload = function() {

  var fixturesContainer = document.querySelector('.fixtures-container');

  FIXTURES.FixturesLoader.load().then(function(fixtures) {

    FIXTURES.NextFixture.setNextFixture(fixtures[0]);

    for (var i = 1; i < fixtures.length; i += 1) {
      var fixtureItem = FIXTURES.Fixture.createFixtureItem(fixtures[i]);
      fixturesContainer.appendChild(fixtureItem);
    }
  })
}
