FIXTURES.Fixture = (function Fixture() {
  var fixtureTemplate = document.getElementById('fixture-template');

  function createFixtureItem(fixture) {
    var fixtureEl = fixtureTemplate.content.cloneNode(true);
    fixtureEl.querySelector('.opponent').innerText = fixture.opponent;
    fixtureEl.querySelector('.competition').innerText = fixture.competition;
    var kickoff = dateFormat(parseISOLocal(fixture.kickoff), "ddd, yyyy mmmm dd, HH:MM");
    fixtureEl.querySelector('.kickoff').innerText = kickoff;
    fixtureEl.querySelector('.crest').style['background-image'] = 'url(assets/crests/' + fixture.badge + ')';
    setType(fixtureEl, fixture);
    return fixtureEl;
  }

  function setType(fixtureEl, fixture) {
    var typeEl = fixtureEl.querySelector('.type');
    typeEl.innerText = fixture.isHomeGame ? 'H' : 'A';
    var typeClass = fixture.isHomeGame ? 'home-game' : 'away-game';
    typeEl.classList.add(typeClass);
  }

  function parseISOLocal(s) {
    var b = s.split(/\D/);
    if (b.length < 6) {
      return;
    }
    var d = new Date(b[0], b[1]-1, b[2], b[3], b[4], b[5]);
    if (typeof d.getMonth === 'function') {
      d.setMilliseconds(d.getMilliseconds() + 60*60*1000);
      return d;
    }
    return s;
  }

  return {
    createFixtureItem: createFixtureItem
  }

}());
