FIXTURES.FixturesLoader = (function() {

  var UNITED_NAME = "Manchester United";
  var fixturesUrl;

  function load() {
    fixturesUrl = FIXTURES.Settings.FIXTURES_URL;
    return getFixtures().then(function(fixtures) {
      return fixtures.map(function(fixture) {
        enrichFixtureWithHomeGameFlag(fixture);
        enrichFixtureWithOpponent(fixture);
        enrichFixtureWithBadge(fixture);
        return fixture;
      }).sort(function(a, b) {
        // newly added fixtures are at the bottom, move logic to the server
        return new Date(a.kickoff).getTime() - new Date(b.kickoff).getTime();
      });
    });
  }

  function getFixtures() {
    return FIXTURES.HttpUtils.getJSON(fixturesUrl);
  }

  function enrichFixtureWithHomeGameFlag(fixture) {
    fixture.isHomeGame = (fixture.homeTeam == UNITED_NAME) ? true : false;
  }

  function enrichFixtureWithOpponent(fixture) {
    if (fixture.isHomeGame) {
      fixture.opponent = fixture.awayTeam;
    } else {
      fixture.opponent = fixture.homeTeam;
    }
  }

  function enrichFixtureWithBadge(fixture) {
    fixture.badge = FIXTURES.BadgeMapper.getBadgeForTeam(fixture.opponent);
  }

  return {
    load: load
  }

}());
